import React from "react";
import { useNavigate } from "react-router-dom";
import "./customerserviceCSS.css";

export const CustomerService = () => {
    const navigate = useNavigate();
    const handleSubmit = (event) => {
        navigate('/');
    };

    const cinemas = {
        '01': {
            versions: ['2D', '3D', 'IMAX'],
            theaters: {
              '2D': ['影城1', '影城2', '影城3'],
              '3D': ['影城4', '影城5'],
              'IMAX': ['影城6', '影城7', '影城8'],
            },
        },
          '02': {
            versions: ['普通版', '豪華版'],
            theaters: {
              '普通版': ['影城9', '影城10'],
              '豪華版': ['影城11', '影城12', '影城13'],
            },
        },
          '03': {
            versions: ['普通版', 'IMAX'],
            theaters: {
              '普通版': ['影城14', '影城15'],
              'IMAX': ['影城16', '影城17'],
            },
        },
    };

    return(
        <form onSubmit={handleSubmit}>
            <div className="name">
                <div className="nameLabel">姓名:</div>
                <input type="text"/>
            </div>
            
            <div className="selectSex">
                <div className="sexLabel">性別:</div>
                <input type="radio" name="sex" value="male"/>男
                <input type="radio" name="sex" value="female"/>女
            </div>

            <div className="inputPhone">
                <div className="phoneLabel">連絡電話:</div>
                <input type="tel"/>
            </div>

            <div className="inputEmail">
                <div className="emailLabel">Email:</div>
                <input type="email"/>
            </div>
            
            <div className="cinema">
                <div className="cinemaLabel">建議之影城:</div>
                <select className="selectCinema">
                    <option></option>
                </select>
            </div>

            <button type="submit">送出您的意見</button>
        </form>
    );
};

export default CustomerService;
